package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class ExcluderCloneTest {

  @Test
  void clone_shouldReturnDistinctInstanceWithEqualFieldValues() {
    Excluder original = new Excluder();
    // set some fields via public methods to change from defaults
    Excluder configured = original.withVersion(1.0)
        .withModifiers(Modifier.PUBLIC)
        .disableInnerClassSerialization()
        .excludeFieldsWithoutExposeAnnotation()
        .withExclusionStrategy((f, t) -> true, true, false);

    Excluder cloned = configured.clone();

    assertNotSame(configured, cloned);
    // check that primitive fields are copied correctly
    assertEquals(configured.version, cloned.version);
    assertEquals(configured.modifiers, cloned.modifiers);
    assertEquals(configured.serializeInnerClasses, cloned.serializeInnerClasses);
    assertEquals(configured.requireExpose, cloned.requireExpose);
    // check that lists are copied (shallow copy, same contents)
    assertEquals(configured.serializationStrategies, cloned.serializationStrategies);
    assertEquals(configured.deserializationStrategies, cloned.deserializationStrategies);
  }

  @Test
  void clone_onDefaultInstance_shouldReturnDistinctInstance() {
    Excluder cloned = Excluder.DEFAULT.clone();
    assertNotSame(Excluder.DEFAULT, cloned);
    assertEquals(Excluder.DEFAULT.version, cloned.version);
    assertEquals(Excluder.DEFAULT.modifiers, cloned.modifiers);
    assertEquals(Excluder.DEFAULT.serializeInnerClasses, cloned.serializeInnerClasses);
    assertEquals(Excluder.DEFAULT.requireExpose, cloned.requireExpose);
    assertEquals(Excluder.DEFAULT.serializationStrategies, cloned.serializationStrategies);
    assertEquals(Excluder.DEFAULT.deserializationStrategies, cloned.deserializationStrategies);
  }
}
